const rawOutput = $json.output || "";

// Remove markdown fences
let cleaned = rawOutput.replace(/```json|```/g, '').trim();

let post = "";
let visual_prompt = "";
let target_audience = "";
let angle = "";

try {
  const parsed = JSON.parse(cleaned);

  post = parsed.post || "";
  visual_prompt = parsed.visual_prompt || 
    "Cinematic AI lab environment, futuristic lighting, ultra-detailed, professional, high resolution";
  target_audience = parsed.target_audience || "";
  angle = parsed.angle || "";

} catch (e) {
  post = cleaned;
  visual_prompt = "Cinematic AI lab environment, futuristic lighting, ultra-detailed, professional, high resolution";
}

return [{
  json: {
    post,
    visual_prompt,
    target_audience,
    angle
  }
}];

// 1. Get the messy output from the Agent
const rawText = $json.output || $json.text || "";

// 2. Extract the prompt using a targeted Regex
// This looks for the text between "image_prompt": and the closing quote
const promptMatch = rawText.match(/"image_prompt":\s*"([^"]+)"/);

let finalPrompt = "";

if (promptMatch && promptMatch[1]) {
    // If we found the JSON value, use it
    finalPrompt = promptMatch[1];
} else {
    // Fallback: If no JSON found, take the last line of text
    const lines = rawText.trim().split('\n');
    finalPrompt = lines[lines.length - 1];
}

// 3. Clean up any remaining artifacts
const cleanPrompt = finalPrompt
    .replace(/[{}]/g, '') // Remove any stray braces
    .trim();

// 4. Return the single string
return {
    json: {
        generate: cleanPrompt
    }
};
